insert into offmarket.business_scores (business_id, score_run_id, layer1_base_rate, layer1_comment, layer2_sellability, layer2_comment, layer3_behavioral_trigger, layer3_comment, layer4_market_pull, layer4_comment, final_score, final_tier, final_comment, value_add_thesis, confidence, data_completeness) values
('206e6d98-d774-54a7-be76-eafcd2955110', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 60, 'Dr. Lide earned his DDS from Baylor College of Dentistry in 1995 and opened his own Richardson practice that year (~31 yrs); license-tenure proxy ~54-58 — approaching but not yet deep in the natural-exit window; solo owner, no associate. Former Baylor instructor (6 yrs). Medium-low confidence (proxy age).', 74, 'Clean ~31-yr solo general/cosmetic family practice in Richardson (75080), recurring hygiene base, good reviews (47 Healthgrades), clean record — a solid, sellable, bankable solo practice.', 55, 'Some coasting tells consistent with a 31-yr solo practice (single provider, dated presence, no visible recent expansion), but the owner is only ~56 and reasonably active — moderate L3.', 84, 'Richardson (Dallas County, near Telecom Corridor) is an active DSO/PE catchment; a clean long-tenured solo GP there is a clean SBA-financed bolt-on. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 66, 'B_forward', 'Dr. Jeffrey S. Lide, ~56 (license_tenure_proxy), runs Jeffrey S. Lide, D.D.S. in Richardson, Dallas County. Dr. Lide earned his DDS from Baylor College of Dentistry in 1995 and opened his own Richardson practice that year (~31 yrs); license-tenure proxy ~54-58 — approaching but not yet deep in the natural-exit window; solo owner, no associate. Former Baylor instructor (6 yrs). Medium-low confidence (proxy age). Some coasting tells consistent with a 31-yr solo practice (single provider, dated presence, no visible recent expansion), but the owner is only ~56 and reasonably active — moderate L3. Richardson (Dallas County, near Telecom Corridor) is an active DSO/PE catchment; a clean long-tenured solo GP there is a clean SBA-financed bolt-on. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 66/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall automation + online scheduling + modern PMS + automated reviews; associate-to-equity path — 2-year EBITDA upside. Re-score in ~18 months as the owner ages further.', 'low', 0.5),
('3e8076fa-dd46-59b2-97ae-a135fc446c4c', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 78, 'Dr. Jack Freudenfeld Jr. has been ''a staple in the Dallas community for decades'' (D Magazine ''Best Dentists'' and Texas Monthly ''Super Dentist'' for many years) — tenure proxy ~64-68, in the natural-exit window. A second dentist (Dr. Amy Horton) provides an internal transition vehicle. Medium-low confidence (proxy age, no firm grad year).', 80, 'Clean, long-established (decades) Walnut Hill/NE Dallas (75231) general/family/cosmetic practice with a strong reputation, 2 providers, ~9 staff, ''98.7% would refer'', clean record — a genuinely sellable, bankable practice in a desirable catchment.', 60, 'Coasting tells: founder near a natural exit, dated web brand, no visible recent expansion beyond the existing associate — but with a 2nd dentist already in place and an active reputation, it''s not strongly disengaged. Moderate L3.', 86, 'NE Dallas / Walnut Hill (75231) is a desirable, in-demand catchment; a reputable 2-provider practice with a long-tenured founder is a clean SBA-financed acquisition or a textbook associate-buy-in. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 74, 'B_forward', 'Dr. Jack Freudenfeld Jr. (with Dr. Amy Horton), ~65 (license_tenure_proxy), runs Woodhill Family Dental (Jack Freudenfeld Jr., DDS) in Dallas, Dallas County. Dr. Jack Freudenfeld Jr. has been ''a staple in the Dallas community for decades'' (D Magazine ''Best Dentists'' and Texas Monthly ''Super Dentist'' for many years) — tenure proxy ~64-68, in the natural-exit window. A second dentist (Dr. Amy Horton) provides an internal transition vehicle. Medium-low confidence (proxy age, no firm grad year). Coasting tells: founder near a natural exit, dated web brand, no visible recent expansion beyond the existing associate — but with a 2nd dentist already in place and an active reputation, it''s not strongly disengaged. Moderate L3. NE Dallas / Walnut Hill (75231) is a desirable, in-demand catchment; a reputable 2-provider practice with a long-tenured founder is a clean SBA-financed acquisition or a textbook associate-buy-in. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 74/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall automation + online scheduling + modern PMS + automated reviews; formalize the associate-to-owner buy-in with Dr. Horton — credible 1.5-2x EBITDA path over 18-24 months.', 'low', 0.45),
('010d6194-fdcd-5da1-b817-dd3f44857de0', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 62, 'Dr. Swift founded Dallas Laser Dentistry in 1997 (~29 yrs as owner) with 30+ yrs in the profession; license-tenure proxy ~56-60 — approaching the natural-exit window. The practice merged with another award-winning Dallas cosmetic practice (so a 2nd dentist is present). Medium-low confidence (proxy age).', 82, 'Strong asset: a ~29-yr cosmetic-led practice in NW Dallas (75231), Consumer''s Choice Award for cosmetic dentistry 2011-2025, Texas Monthly Super Dentist 2014-2025, 2 providers, ~8 staff, high ratings, clean record — very sellable and bankable in a premium niche.', 46, 'Mixed: established owner approaching exit and a 29-yr practice lean coasting, but a cosmetic practice that''s still racking up annual awards and actively marketing isn''t strongly disengaged. Moderate-low L3.', 88, 'Premium cosmetic-led practices in Dallas are top buy-side targets — easy SBA financing, strong DSO and high-net-worth-dentist demand. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 66, 'B_forward', 'Dr. Mary Swift, ~58 (license_tenure_proxy), runs Dallas Laser Dentistry (Mary Swift, DDS) in Dallas, Dallas County. Dr. Swift founded Dallas Laser Dentistry in 1997 (~29 yrs as owner) with 30+ yrs in the profession; license-tenure proxy ~56-60 — approaching the natural-exit window. The practice merged with another award-winning Dallas cosmetic practice (so a 2nd dentist is present). Medium-low confidence (proxy age). Mixed: established owner approaching exit and a 29-yr practice lean coasting, but a cosmetic practice that''s still racking up annual awards and actively marketing isn''t strongly disengaged. Moderate-low L3. Premium cosmetic-led practices in Dallas are top buy-side targets — easy SBA financing, strong DSO and high-net-worth-dentist demand. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 66/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + concierge recall, online scheduling, modern PMS, automated reviews, structured high-value cosmetic-case marketing, plus an associate-to-equity glide path — the brand supports premium pricing, so the lever is throughput and case acceptance.', 'low', 0.45),
('15385e01-c501-5fc4-b82b-3828604a1ae1', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 45, 'Practice family-owned in Garland since 1971 (~55 yrs), but the current principal dentist''s age, tenure, and whether it''s a single-family or multi-family/group ownership are not verified — treat L1 as moderate/uncertain. Low confidence; needs an ownership + TSBDE check.', 78, 'A real, long-established (55-yr) Garland general/family practice with 4 dentists, ~14 staff, a deep multigenerational recurring base, clean record — clearly financeable and of meaningful size; the unknown is owner structure.', 40, 'A 4-doctor practice that''s stayed family-owned for 55 yrs could be either coasting (aging principal) or actively run by a younger family member — no decline stack verified. Moderate-low L3, low confidence.', 84, 'Garland (Dallas County) has steady DSO interest; a 55-yr, 4-dentist practice with a deep base is a strong roll-up target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 58, 'C_watch', 'Owner, age unknown, runs Musso Family Dentistry in Garland, Dallas County. Practice family-owned in Garland since 1971 (~55 yrs), but the current principal dentist''s age, tenure, and whether it''s a single-family or multi-family/group ownership are not verified — treat L1 as moderate/uncertain. Low confidence; needs an ownership + TSBDE check. A 4-doctor practice that''s stayed family-owned for 55 yrs could be either coasting (aging principal) or actively run by a younger family member — no decline stack verified. Moderate-low L3, low confidence. Garland (Dallas County) has steady DSO interest; a 55-yr, 4-dentist practice with a deep base is a strong roll-up target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 58/100. Tier C — re-score in ~90 days.', 'Pending ownership verification: standard recall/AI/scheduling/PMS stack across the practice. Verify principal age and ownership structure before acting.', 'low', 0.3),
('330d6f01-55d4-50bb-9698-70f5bb730e95', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 30, 'Dr. Randall (Texas A&M/Baylor College of Dentistry DDS) appears clearly mid-career; tenure proxy ~44-50 — not near a natural-exit window. A second dentist (Dr. Scott Evans) is present. Low L1.', 76, 'Clean, well-regarded University Park/Park Cities (75205) family practice, 2 providers, ~8 staff, recurring base, clean record — a real, financeable, attractive practice in a premium catchment; the owner just isn''t a seller.', 26, 'Not coasting — active marketing, 2 providers, mid-career owner. Low L3.', 88, 'University Park / Park Cities (75205) is a top buy-side target; a 2-provider family practice there is a prized bolt-on — but the owner isn''t selling. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 49, 'C_watch', 'Dr. Drew Randall (with Dr. Scott Evans), ~48 (license_tenure_proxy), runs Randall Dentistry (Drew Randall, DDS) in University Park, Dallas County. Dr. Randall (Texas A&M/Baylor College of Dentistry DDS) appears clearly mid-career; tenure proxy ~44-50 — not near a natural-exit window. A second dentist (Dr. Scott Evans) is present. Low L1. Not coasting — active marketing, 2 providers, mid-career owner. Low L3. University Park / Park Cities (75205) is a top buy-side target; a 2-provider family practice there is a prized bolt-on — but the owner isn''t selling. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 49/100. Tier C — re-score in ~90 days.', 'N/A near-term — owner not winding down. Watch.', 'low', 0.4),
('b68030e2-700b-59b3-a259-e273228c31e2', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 45, 'The named dentists'' ages and tenure aren''t verified; an established Preston Hollow Village (75230) practice — treat L1 as neutral/uncertain. Low confidence; needs a TSBDE issue-date check.', 74, 'A real, operating 2-provider general/cosmetic/implant practice in an affluent N Dallas corridor, ~8 staff, recurring base — financeable, pending verification of size and ownership.', 42, 'No verified coasting tells; reasonably maintained presence. Moderate-low L3, low confidence.', 86, 'Preston Hollow / N Dallas (75230) is a desirable catchment with strong DSO interest. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 58, 'C_watch', 'Drs. Celeste Latham & Chi Trieu, age unknown, runs Lovers Lane Dental Associates in Dallas, Dallas County. The named dentists'' ages and tenure aren''t verified; an established Preston Hollow Village (75230) practice — treat L1 as neutral/uncertain. Low confidence; needs a TSBDE issue-date check. No verified coasting tells; reasonably maintained presence. Moderate-low L3, low confidence. Preston Hollow / N Dallas (75230) is a desirable catchment with strong DSO interest. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 58/100. Tier C — re-score in ~90 days.', 'Pending verification: standard recall/AI/scheduling/PMS stack. Verify owner age and practice age before acting.', 'low', 0.3),
('e5bc4cba-897c-5d8e-afaf-dc80412a4a25', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 42, 'Dr. Kaliher graduated UT Dental Branch Houston in 2000 (~26 yrs licensed; USAF dental residency after); license-tenure proxy ~48-52 — approaching but not yet in the prime exit window. Low-medium L1.', 74, 'Clean general dentistry practice in central Austin''s medical district (78756, near Allandale/Tarrytown/Old West Austin), recurring hygiene base, AGD/TDA/ADA member, good reviews — a solid, sellable, bankable solo practice; SBA-financeable.', 50, 'Some coasting tells: Mon-Thu 7-3:30 only (4-day, early-out week) and a single provider — but the owner is only ~50 and the presence is reasonably maintained. Moderate L3.', 86, 'Central Austin''s medical district (78756) is a premium, supply-constrained, high-demand catchment; a clean solo GP there is a prime SBA-financed acquisition. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 59, 'C_watch', 'Dr. Trey Kaliher, ~50 (license_tenure_proxy), runs Trey Kaliher, D.D.S. in Austin, Travis County. Dr. Kaliher graduated UT Dental Branch Houston in 2000 (~26 yrs licensed; USAF dental residency after); license-tenure proxy ~48-52 — approaching but not yet in the prime exit window. Low-medium L1. Some coasting tells: Mon-Thu 7-3:30 only (4-day, early-out week) and a single provider — but the owner is only ~50 and the presence is reasonably maintained. Moderate L3. Central Austin''s medical district (78756) is a premium, supply-constrained, high-demand catchment; a clean solo GP there is a prime SBA-financed acquisition. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 59/100. Tier C — re-score in ~90 days.', 'AI front desk + recall automation + online scheduling + modern PMS + automated reviews; associate-to-equity path — 2-year EBITDA upside. Re-score in ~3 yrs as the owner ages, or forward now to a searcher who wants a central-Austin foothold.', 'low', 0.45),
('9ac995ba-02e8-5a81-932d-0217879b1514', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 46, 'Dr. Montreuil earned his DDS from LSU School of Dentistry in 1996 (~30 yrs licensed) and entered this Round Rock private practice in December 2006 (~20 yrs as owner); license-tenure proxy ~50-55 — approaching but not yet in the prime exit window. Williamson County (Round Rock), adjacent to Travis — deprioritized. Low-medium L1.', 72, 'Clean ~20-yr solo family/cosmetic/Invisalign/implant practice in Round Rock (78681), recurring hygiene base, decent reviews, clean record — a solid, sellable, bankable solo practice in a high-growth suburb. Williamson County caps priority slightly.', 50, 'Some coasting potential in a 20-yr solo practice (single provider, modest review count), but the owner is only ~53 and the presence is reasonably maintained. Moderate L3.', 82, 'Round Rock / Williamson County is a high-growth Austin-metro suburb with active DSO interest; just outside the core 3 counties. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 59, 'C_watch', 'Dr. William J. Montreuil, ~53 (license_tenure_proxy), runs Dental Health Center of Round Rock (William J. Montreuil, DDS) in Round Rock, Williamson County. Dr. Montreuil earned his DDS from LSU School of Dentistry in 1996 (~30 yrs licensed) and entered this Round Rock private practice in December 2006 (~20 yrs as owner); license-tenure proxy ~50-55 — approaching but not yet in the prime exit window. Williamson County (Round Rock), adjacent to Travis — deprioritized. Low-medium L1. Some coasting potential in a 20-yr solo practice (single provider, modest review count), but the owner is only ~53 and the presence is reasonably maintained. Moderate L3. Round Rock / Williamson County is a high-growth Austin-metro suburb with active DSO interest; just outside the core 3 counties. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 59/100. Tier C — re-score in ~90 days.', 'AI front desk + recall automation + online scheduling + modern PMS + automated reviews; associate-to-equity path — 2-year EBITDA upside in a growth suburb. Re-score in ~2-3 yrs.', 'low', 0.45)
